MERGE INTO CONSULTAS FIN USING (SELECT '002274SubIndProductoTocanPR' INFORME ,TO_CLOB(q'[SELECT DISTINCT
BP_PLAN_INDICATIVO.DESCRIPCION_INDICADOR META_PRODUCTO
FROM BP_D_NOVEDADPROYECTO
LEFT JOIN BP_PLAN_INDICATIVO
   ON BP_D_NOVEDADPROYECTO.COMPANIA                  = BP_PLAN_INDICATIVO.COMPANIA 
  AND BP_D_NOVEDADPROYECTO.ID_META_PRODUCTO          = BP_PLAN_INDICATIVO.ID
  AND BP_D_NOVEDADPROYECTO.VIGENCIA_PLAN_INDICATIVO  = BP_PLAN_INDICATIVO.VIGENCIA_INICIAL
WHERE
	BP_D_NOVEDADPROYECTO.COMPANIA = '$P!{PR_COMPANIA}'
	AND BP_D_NOVEDADPROYECTO.TIPOT = '$P!{PR_TIPOT}'
	AND BP_D_NOVEDADPROYECTO.CLASET = '$P!{PR_CLASET}'
	AND BP_D_NOVEDADPROYECTO.NOVEDAD = '$P!{PR_CONSECUTIVO}']') CONSULTA, 52 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);

	MERGE INTO CONSULTAS_SUB FIN USING (SELECT '001771CDPTOCAN' INFORME_PADRE, '002274SubIndProductoTocanPR' INFORME_HIJO, 'PR_STRSQL_SUB_INDPRODUCTO' PARAMETRO ,NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);
	